+    // Cooldown = 3 epochs. Deopt at 97. Current at 100.
+    // 100 - 97 = 3, which is NOT < 3, so cooldown should be inactive
+    assert!(!cooldown_active(&p, 3, &SecurityEpoch::from_raw(100)));
+}
