+#[test]
+fn add_probe_generates_unique_ids() {
+    let mut p = TierProfile::new("ap0", "fn_probes");
+    add_probe(&mut p, ProbeKind::TypeProfile, "s0", 10, 100);
+    add_probe(&mut p, ProbeKind::TypeProfile, "s0", 20, 200);
